mapper.insert:
INSERT INTO STOCK_REALTIME_TICK ( TICK_ID, STOCK_CODE, CURRENT_PRICE, CHANGE_RATE, VOLUME, TRADE_TIME ) SELECT SEQ_STOCK_REALTIME_TICK.NEXTVAL, A.STOCK_CODE, A.CURRENT_PRICE, A.CHANGE_RATE, A.VOLUME, A.TRADE_TIME FROM (
SELECT #{item.stockCode} AS STOCK_CODE, #{item.currentPrice} AS CURRENT_PRICE, #{item.changeRate} AS CHANGE_RATE, #{item.volume} AS VOLUME, #{item.tradeTime} AS TRADE_TIME FROM DUAL
) A

mapper.update:
    UPDATE CO_INFORMATION
       SET ISSUED_STOCK      = #{issuedStock},
           DECLINED_STOCK    = #{declinedStock},
           TREASURY_STOCK    = #{treasuryStock},
		   OUTSTANDING_SHARES = #{outstandingShares}
     WHERE STOCK_CODE = #{stockCode}

    UPDATE CO_INFORMATION
    SET
        MINORITY_SHAREHOLDER_RATIO = #{minorityShareholderRatio},
		MINORITY_OWNERSHIP_RATIO   = #{minorityOwnershipRatio}
    WHERE STOCK_CODE = #{stockCode}

mapper.insert:
MERGE INTO STOCK_HISTORY_CACHE t USING ( SELECT #{stockCode} AS STOCK_CODE, #{periodType} AS PERIOD_TYPE, #{baseDate} AS BASE_DATE FROM dual ) s ON ( t.STOCK_CODE = s.STOCK_CODE AND t.PERIOD_TYPE = s.PERIOD_TYPE AND t.BASE_DATE = s.BASE_DATE )
WHEN MATCHED THEN UPDATE SET OPEN_PRICE = #{openPrice}, HIGH_PRICE = #{highPrice}, LOW_PRICE = #{lowPrice}, CLOSE_PRICE = #{closePrice}, VOLUME = #{volume}, CHANGE_PRICE = #{changePrice}, CHANGE_RATE = #{changeRate}
WHEN NOT MATCHED THEN INSERT ( HISTORY_ID, STOCK_CODE, PERIOD_TYPE, BASE_DATE, OPEN_PRICE, HIGH_PRICE, LOW_PRICE, CLOSE_PRICE, VOLUME, CHANGE_PRICE, CHANGE_RATE ) VALUES ( SEQ_STOCK_HISTORY_CACHE.NEXTVAL, #{stockCode}, #{periodType}, #{baseDate}, #{openPrice}, #{highPrice}, #{lowPrice}, #{closePrice}, #{volume}, #{changePrice}, #{changeRate} )
